const data = $input.first().json;
const m = new Date().getMonth() + 1;
const season = (m === 12 || m <= 2) ? 'winter' : (m <= 5) ? 'summer' : (m <= 9) ? 'monsoon' : 'postmonsoon';
const originalStr = JSON.stringify(data);
const prompt = `You maintain the city air profiles for AirFloor (airfloor.netlify.app), a free air-health tool for India.

Below is the current cityprofiles JSON: 50 Indian cities, each with name {en,te,kn} and p {en,te,kn}, where each language has the fields general, winter, summer, monsoon, postmonsoon.

TASK: lightly refresh ONLY the "general" and "${season}" fields in all three languages for every city. Improve naturalness and freshness of wording while keeping every fact and the meaning identical. Telugu and Kannada must read like a knowledgeable local wrote them, never like a translation. Leave ids, lat, lon, names, and every other season field byte-identical. Never use an em-dash, section symbol, emoji, or bullet dot; use "|" or commas. Each field stays one sentence of about 15 to 25 words.

Return ONLY the complete JSON document with the exact same structure and the key "cities".

JSON:
${originalStr}`;
return [{ json: { prompt, season, originalStr } }];

const crypto = require('crypto');
const resp = $input.first().json;
const season = $('Build prompt').first().json.season;
const original = JSON.parse($('Build prompt').first().json.originalStr);
const content = resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content;
if (!content) throw new Error('LLM returned no content');
let fresh;
try { fresh = JSON.parse(content); } catch (e) { throw new Error('LLM output is not valid JSON: ' + e.message); }
const cities = fresh.cities;
if (!Array.isArray(cities) || cities.length !== original.cities.length) throw new Error('City count changed: ' + (cities ? cities.length : 'none'));
const SEASONS = ['general','winter','summer','monsoon','postmonsoon'];
const LANGS = ['en','te','kn'];
const banned = /[\u2014\u00b7\u2022\u00a7]|[\u{1F000}-\u{1FAFF}]/u;
let changed = 0; const samples = [];
for (let i = 0; i < original.cities.length; i++) {
  const o = original.cities[i]; const f = cities[i];
  if (!f || f.id !== o.id) throw new Error('City id mismatch at index ' + i);
  f.lat = o.lat; f.lon = o.lon; f.name = o.name;
  for (const L of LANGS) {
    if (!f.p || !f.p[L]) throw new Error('Missing lang ' + L + ' for ' + o.id);
    for (const S of SEASONS) {
      const isRefreshable = (S === 'general' || S === season);
      if (!isRefreshable) { f.p[L][S] = o.p[L][S]; continue; }
      const t = f.p[L][S];
      if (typeof t !== 'string' || t.trim().length < 20) throw new Error('Bad text ' + o.id + '.' + L + '.' + S);
      if (banned.test(t)) throw new Error('Banned character in ' + o.id + '.' + L + '.' + S);
      if (t !== o.p[L][S]) { changed++; if (samples.length < 5) samples.push(o.id + '.' + L + '.' + S + ': ' + t.slice(0, 90)); }
    }
  }
}
fresh.updated = new Date().toISOString().slice(0, 10);
const newStr = JSON.stringify(fresh);
const sha1 = crypto.createHash('sha1').update(newStr).digest('hex');
return [{ json: { newStr, sha1, changed, season, samples } }];

