const files = $input.all().map(i => i.json);
const digest = {};
for (const f of files) { if (f.path && f.sha) digest[f.path] = f.sha; }
const v = $('Validate').first().json;
digest['/cityprofiles.json'] = v.sha1;
return [{ json: { digest, newStr: v.newStr, season: v.season, changed: v.changed } }];

